# ---------- HELPER ----------
def cards_html(category):
    items = [a for a in ARTICLES if a["cat"] == category]
    parts = []
    for a in items:
        parts.append(f'''
        <div class="news-card" data-article-id="{a['id']}" data-category="{a['cat']}">
            <div class="card-content">
                <span class="card-category">{a['cat_label']}</span>
                <h3 class="card-title">{a['title']}</h3>
                <p class="card-summary">{a['summary']}</p>
                <div class="card-footer">
                    <a href="articles/{DATE_ISO}-{a['id']}.html" class="read-more">קרא עוד ←</a>
                    <div class="rating-buttons">
                        <button class="rating-btn" data-article-id="{a['id']}" data-rating="up">👍</button>
                        <button class="rating-btn" data-article-id="{a['id']}" data-rating="down">👎</button>
                    </div>
                </div>
            </div>
        </div>''')
    return "\n".join(parts)

