def build_news_grid():
    blocks = []
    for cat in CATEGORY_ORDER:
        items = [a for a in ARTICLES if a["cat"] == cat]
        if not items:
            continue
        icon, label = CATEGORY_LABELS[cat]
        blocks.append(f'''<section class="section-block news-section" id="{cat}">
                <div class="section-header">
                    <span class="section-icon">{icon}</span>
                    <h2 class="section-title">{label}</h2>
                </div>
                <div class="news-cards">{cards_html(cat)}
                </div>
            </section>''')
    return "\n            ".join(blocks)

